INSERT INTO `faqs` (`id`, `question`, `answer`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'Mô hình xe có được bọc chống sốc không?', 'Có. Tất cả mô hình JDM trước khi giao đều được bọc nhiều lớp chống sốc và đóng hộp cẩn thận để hạn chế trầy xước hoặc móp hộp trong quá trình vận chuyển.', 1, '2026-06-27 01:03:23', '2026-06-27 01:03:23'),
(2, 'Thời gian giao hàng là bao lâu?', 'Đơn hàng nội thành thường mất 1-2 ngày làm việc. Các tỉnh thành khác thường từ 3-5 ngày làm việc tùy khu vực và đơn vị vận chuyển.', 1, '2026-06-27 01:03:23', '2026-06-27 01:03:23'),
(3, 'Tôi có thể kiểm tra hàng trước khi thanh toán không?', 'Bạn có thể kiểm tra tình trạng bên ngoài của gói hàng khi nhận. Với các đơn COD, vui lòng quay video mở hộp để được hỗ trợ nhanh hơn nếu có vấn đề phát sinh.', 1, '2026-06-27 01:03:23', '2026-06-27 01:03:23'),
(4, 'Nếu mô hình bị lỗi hoặc thiếu phụ kiện thì phải làm sao?', 'Hãy gửi yêu cầu qua form hỗ trợ kèm thông tin đơn hàng và mô tả lỗi. Đội ngũ CSKH sẽ phản hồi để hỗ trợ đổi trả hoặc xử lý trong thời gian sớm nhất.', 1, '2026-06-27 01:03:23', '2026-06-27 01:03:23');

