--
-- Bẫy `order_items`
--
DROP TRIGGER IF EXISTS `check_stock_before_order`;
DELIMITER $$
CREATE TRIGGER `check_stock_before_order` BEFORE INSERT ON `order_items` FOR EACH ROW BEGIN

    DECLARE current_stock INT;

    SELECT stock
    INTO current_stock
    FROM products
    WHERE id = NEW.product_id
    FOR UPDATE;

    IF current_stock < NEW.quantity THEN

        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT='Out of stock';

    END IF;

END
$$
DELIMITER ;

