(49, 'Toyota', 'Supra MK5', '1:32', 260000.00, 'Đen', 50, 'toyota_supra_mk5_black.jpg', 'Toyota GR Supra Mk5 (còn gọi là A90, ra mắt vào năm 2019) là một chiếc xe thể thao hai chỗ ngồi rất được mong đợi, đánh dấu sự trở lại của huyền thoại Supra sau 17 năm vắng bóng.', '2026-04-23 17:22:44', 0, 5, 1, NULL, NULL),
(50, 'Toyota', 'Supra MK5', '1:32', 250000.00, 'Trắng', 50, 'toyota_mk5_white.jpg', 'Toyota GR Supra Mk5 (còn gọi là A90, ra mắt vào năm 2019) là một chiếc xe thể thao hai chỗ ngồi rất được mong đợi, đánh dấu sự trở lại của huyền thoại Supra sau 17 năm vắng bóng.', '2026-04-23 17:22:44', 0, 5, 1, NULL, NULL),
