(57, 'Toyota', 'GT86', '1:32', 290000.00, 'Xanh Dương Đen', 50, 'toyota_gt86_black_blue.jpg', 'GT86 là kết quả của sự hợp tác kỹ thuật giữa Toyota và Subaru. Cả hai công ty cùng phát triển khung gầm và hệ thống truyền động, dẫn đến hai mẫu xe song sinh là Toyota GT86 và Subaru BRZ.', '2026-04-23 17:50:59', 0, 5, 1, NULL, NULL),
(58, 'Toyota', 'GT86', '1:32', 280000.00, 'Vàng Đen', 50, 'toyota_gt86_black_yellow.jpg', 'GT86 là kết quả của sự hợp tác kỹ thuật giữa Toyota và Subaru. Cả hai công ty cùng phát triển khung gầm và hệ thống truyền động, dẫn đến hai mẫu xe song sinh là Toyota GT86 và Subaru BRZ.', '2026-04-23 17:50:59', 0, 5, 1, NULL, NULL),
(59, 'Toyota', 'GT86', '1:32', 260000.00, 'Xám', 50, 'toyota_gt86_gray.jpg', 'GT86 là kết quả của sự hợp tác kỹ thuật giữa Toyota và Subaru. Cả hai công ty cùng phát triển khung gầm và hệ thống truyền động, dẫn đến hai mẫu xe song sinh là Toyota GT86 và Subaru BRZ.', '2026-04-23 17:50:59', 0, 5, 1, NULL, NULL),
(60, 'Toyota', 'GT86', '1:32', 260000.00, 'Trắng', 50, 'toyota_gt86_white.jpg', 'GT86 là kết quả của sự hợp tác kỹ thuật giữa Toyota và Subaru. Cả hai công ty cùng phát triển khung gầm và hệ thống truyền động, dẫn đến hai mẫu xe song sinh là Toyota GT86 và Subaru BRZ.', '2026-04-23 17:50:59', 0, 5, 1, NULL, NULL),
(61, 'Toyota', 'MR2', '1:32', 231000.00, 'Đỏ', 50, 'toyota_mr2_red.jpg', 'Toyota MR2 là một chiếc xe thể thao rất độc đáo và thú vị của Toyota, nổi tiếng với bố cục động cơ đặt giữa (Mid-engine, Rear-wheel drive, 2-seater), mang lại khả năng xử lý sắc nét như một chiếc siêu xe thu nhỏ.', '2026-04-23 18:00:24', 0, 5, 1, NULL, NULL),
(62, 'Toyota', 'MR2', '1:32', 233000.00, 'Trắng', 50, 'toyota_mr2_white.jpg', 'Toyota MR2 là một chiếc xe thể thao rất độc đáo và thú vị của Toyota, nổi tiếng với bố cục động cơ đặt giữa (Mid-engine, Rear-wheel drive, 2-seater), mang lại khả năng xử lý sắc nét như một chiếc siêu xe thu nhỏ.', '2026-04-23 18:00:24', 0, 5, 1, NULL, NULL),
(63, 'Toyota', 'MR2', '1:32', 232000.00, 'Đen', 50, 'toyota_mr2_black.jpg', 'Toyota MR2 là một chiếc xe thể thao rất độc đáo và thú vị của Toyota, nổi tiếng với bố cục động cơ đặt giữa (Mid-engine, Rear-wheel drive, 2-seater), mang lại khả năng xử lý sắc nét như một chiếc siêu xe thu nhỏ.', '2026-04-23 18:00:24', 0, 5, 1, NULL, NULL),
(64, 'Toyota', 'MR2', '1:64', 235000.00, 'Cam', 50, 'toyota_mr2_orange.jpg', 'Toyota MR2 là một chiếc xe thể thao rất độc đáo và thú vị của Toyota, nổi tiếng với bố cục động cơ đặt giữa (Mid-engine, Rear-wheel drive, 2-seater), mang lại khả năng xử lý sắc nét như một chiếc siêu xe thu nhỏ.', '2026-04-23 18:00:24', 0, 5, 1, NULL, NULL),
(65, 'Toyota', 'Celica', '1:32', 240000.00, 'Trắng', 50, 'toyota_celica_white.jpg', 'Toyota Celica là một dòng xe thể thao coupe/liftback mang tính biểu tượng của Toyota, được sản xuất qua bảy thế hệ (từ 1970 đến 2006). Không giống như Supra (động cơ I6 lớn) hay MR2 (động cơ đặt giữa), Celica nổi tiếng là một chiếc xe thể thao dẫn động cầu trước (FWD) tập trung vào phong cách và khả năng xử lý linh hoạt.\r\n\r\nĐiểm làm nên huyền thoại của Celica là phiên bản hiệu năng cao Celica GT-Four (sử dụng dẫn động bốn bánh - AWD), thống trị các giải đua WRC (World Rally Championship) trong thập niên 80 và 90.', '2026-04-24 02:40:18', 0, 5, 1, NULL, NULL),
(66, 'Toyota', 'Celica', '1:32', 250000.00, 'Đen', 50, 'toyota_celica_black.jpg', 'Toyota Celica là một dòng xe thể thao coupe/liftback mang tính biểu tượng của Toyota, được sản xuất qua bảy thế hệ (từ 1970 đến 2006). Không giống như Supra (động cơ I6 lớn) hay MR2 (động cơ đặt giữa), Celica nổi tiếng là một chiếc xe thể thao dẫn động cầu trước (FWD) tập trung vào phong cách và khả năng xử lý linh hoạt.\r\n\r\nĐiểm làm nên huyền thoại của Celica là phiên bản hiệu năng cao Celica GT-Four (sử dụng dẫn động bốn bánh - AWD), thống trị các giải đua WRC (World Rally Championship) trong thập niên 80 và 90.', '2026-04-24 02:40:18', 0, 5, 1, NULL, NULL),
(67, 'Toyota', 'Celica', '1:32', 260000.00, 'Xanh Dương', 50, 'toyota_celica_blue.jpg', 'Toyota Celica là một dòng xe thể thao coupe/liftback mang tính biểu tượng của Toyota, được sản xuất qua bảy thế hệ (từ 1970 đến 2006). Không giống như Supra (động cơ I6 lớn) hay MR2 (động cơ đặt giữa), Celica nổi tiếng là một chiếc xe thể thao dẫn động cầu trước (FWD) tập trung vào phong cách và khả năng xử lý linh hoạt.\r\n\r\nĐiểm làm nên huyền thoại của Celica là phiên bản hiệu năng cao Celica GT-Four (sử dụng dẫn động bốn bánh - AWD), thống trị các giải đua WRC (World Rally Championship) trong thập niên 80 và 90.', '2026-04-24 02:40:18', 0, 5, 1, NULL, NULL),
(68, 'Toyota', 'AE86 Levin', '1:32', 290000.00, 'Đỏ Đen', 50, 'toyota_ae86_levin_blackred.jpg', 'Levin là người anh em song sinh về mặt cơ khí của Trueno, sử dụng cùng khung gầm RWD và động cơ 4A-GE mạnh mẽ. Điểm khác biệt duy nhất là Levin được trang bị đèn pha cố định (fixed headlights), khiến đầu xe có hình dáng vuông vức và góc cạnh hơn. Mặc dù ít xuất hiện trong văn hóa đại chúng hơn Trueno, Levin vẫn được các tín đồ JDM săn đón không kém nhờ triết lý thiết kế đơn giản, sự bền bỉ của động cơ 4A-GE và khả năng xử lý sắc nét, tập trung vào niềm vui lái xe thuần túy.', '2026-04-24 02:56:23', 0, 5, 1, NULL, NULL),
(69, 'Toyota', 'AE86 Levin', '1:32', 290000.00, 'Vàng Đen', 50, 'toyota_ae86_levin_blackyellow.jpg', 'Levin là người anh em song sinh về mặt cơ khí của Trueno, sử dụng cùng khung gầm RWD và động cơ 4A-GE mạnh mẽ. Điểm khác biệt duy nhất là Levin được trang bị đèn pha cố định (fixed headlights), khiến đầu xe có hình dáng vuông vức và góc cạnh hơn. Mặc dù ít xuất hiện trong văn hóa đại chúng hơn Trueno, Levin vẫn được các tín đồ JDM săn đón không kém nhờ triết lý thiết kế đơn giản, sự bền bỉ của động cơ 4A-GE và khả năng xử lý sắc nét, tập trung vào niềm vui lái xe thuần túy.', '2026-04-24 02:56:23', 0, 5, 1, NULL, NULL),
