(74, 'Toyota', 'AE86 Trueno  Panda', '1:32', 260000.00, 'Đen', 45, 'toyota_ae86_trueno_black.jpg', 'Trueno là phiên bản AE86 nổi tiếng nhất với đặc trưng là đèn pha bật/mở (pop-up headlights). Khi đèn tắt, mũi xe trở nên mượt mà và khí động học, mang lại vẻ ngoài cổ điển của một chiếc xe thể thao thập niên 80. Về cơ khí, nó sử dụng động cơ huyền thoại 4A-GE 1.6L, DOHC, 16 van, kết hợp với hệ dẫn động cầu sau (RWD) và trọng lượng nhẹ (dưới 1 tấn), khiến nó trở thành chiếc xe hoàn hảo cho việc drift và xử lý cân bằng. Trueno Hatchback (màu Panda) là chiếc xe biểu tượng trong series Initial D thuộc về Takumi Fujiwara.', '2026-04-24 03:16:21', 0, 5, 1, NULL, NULL),
(75, 'Subaru', 'Impreza', '1:32', 280000.00, 'Trắng', 40, 'subaru_impreza_white.jpg', 'Subaru Impreza là một dòng xe rất quan trọng đối với Subaru, nổi tiếng toàn cầu vì hệ dẫn động bốn bánh toàn thời gian (AWD) tiêu chuẩn và di sản rực rỡ trong các giải đua Rally.Phần lớn danh tiếng của Impreza đến từ các phiên bản hiệu năng cao, đặc biệt là WRX (World Rally eXperimental) và WRX STI (Subaru Tecnica International).', '2026-04-24 03:45:17', 0, 5, 1, NULL, NULL),
(76, 'Subaru', 'Impreza', '1:32', 220000.00, 'Đen', 40, 'subaru_impreza_black.jpg', 'Subaru Impreza là một dòng xe rất quan trọng đối với Subaru, nổi tiếng toàn cầu vì hệ dẫn động bốn bánh toàn thời gian (AWD) tiêu chuẩn và di sản rực rỡ trong các giải đua Rally.Phần lớn danh tiếng của Impreza đến từ các phiên bản hiệu năng cao, đặc biệt là WRX (World Rally eXperimental) và WRX STI (Subaru Tecnica International).', '2026-04-24 03:45:17', 0, 5, 1, NULL, NULL),
