(80, 'Nissan', 'Silvia S15', '1:32', 290000.00, 'Cam Đen', 50, 'nissan_silvia_s15_black_orange.jpg', 'Nissan Silvia S15 là một trong những chiếc xe thể thao được yêu thích nhất của Nissan và được coi là đỉnh cao, là thế hệ cuối cùng của dòng xe Silvia huyền thoại.S15 sử dụng phiên bản cuối cùng và mạnh mẽ nhất của dòng động cơ SR của Nissan.Nissan Silvia S15 là một chiếc xe có giá trị sưu tầm rất cao trên toàn thế giới. Sau khi ngừng sản xuất, sự vắng bóng của một chiếc coupe thể thao RWD giá cả phải chăng đã tạo nên một lỗ hổng lớn.', '2026-04-24 03:59:56', 0, 5, 1, NULL, NULL),
(81, 'Nissan', 'Silvia S15', '1:32', 300000.00, 'Vàng Đen', 50, 'nissan_silvia_s15_blackyellow.jpg', 'Nissan Silvia S15 là một trong những chiếc xe thể thao được yêu thích nhất của Nissan và được coi là đỉnh cao, là thế hệ cuối cùng của dòng xe Silvia huyền thoại.S15 sử dụng phiên bản cuối cùng và mạnh mẽ nhất của dòng động cơ SR của Nissan.Nissan Silvia S15 là một chiếc xe có giá trị sưu tầm rất cao trên toàn thế giới. Sau khi ngừng sản xuất, sự vắng bóng của một chiếc coupe thể thao RWD giá cả phải chăng đã tạo nên một lỗ hổng lớn.', '2026-04-24 03:59:56', 0, 5, 1, NULL, NULL),
