(84, 'Nissan', 'Silvia S13', '1:32', 260000.00, 'Xanh Dương', 50, 'nissan_silvia_s13_blue.jpg', 'Nissan S13 là thế hệ đã biến dòng Silvia thành một biểu tượng toàn cầu về khả năng drift và độ xe.S13 mang phong cách thiết kế gọn gàng, vuông vức nhưng thanh thoát, rất đặc trưng của cuối thập niên 80.Linh hồn S13: Động cơ SR20DET (đặc biệt là bản \"Red Top\" hoặc \"Black Top\") được tôn sùng vì tiềm năng độ chế khổng lồ, là động cơ tiêu chuẩn cho xe drift.', '2026-04-24 04:06:51', 0, 5, 1, NULL, NULL),
(85, 'Nissan', 'Silvia S13', '1:32', 260000.00, 'Đen', 50, 'nissan_silvia_s13_black.jpg', 'Nissan S13 là thế hệ đã biến dòng Silvia thành một biểu tượng toàn cầu về khả năng drift và độ xe.S13 mang phong cách thiết kế gọn gàng, vuông vức nhưng thanh thoát, rất đặc trưng của cuối thập niên 80.Linh hồn S13: Động cơ SR20DET (đặc biệt là bản \"Red Top\" hoặc \"Black Top\") được tôn sùng vì tiềm năng độ chế khổng lồ, là động cơ tiêu chuẩn cho xe drift.', '2026-04-24 04:06:51', 0, 5, 1, NULL, NULL),
(86, 'Nissan', 'Silvia S13', '1:32', 250000.00, 'Đỏ', 50, 'nissan_silvia_s13_red.jpg', 'Nissan S13 là thế hệ đã biến dòng Silvia thành một biểu tượng toàn cầu về khả năng drift và độ xe.S13 mang phong cách thiết kế gọn gàng, vuông vức nhưng thanh thoát, rất đặc trưng của cuối thập niên 80.Linh hồn S13: Động cơ SR20DET (đặc biệt là bản \"Red Top\" hoặc \"Black Top\") được tôn sùng vì tiềm năng độ chế khổng lồ, là động cơ tiêu chuẩn cho xe drift.', '2026-04-24 04:06:51', 0, 5, 1, NULL, NULL),
(87, 'Nissan', 'Silvia S13', '1:32', 270000.00, 'Trắng', 50, 'nissan_silvia_s13_white.jpg', 'Nissan S13 là thế hệ đã biến dòng Silvia thành một biểu tượng toàn cầu về khả năng drift và độ xe.S13 mang phong cách thiết kế gọn gàng, vuông vức nhưng thanh thoát, rất đặc trưng của cuối thập niên 80.Linh hồn S13: Động cơ SR20DET (đặc biệt là bản \"Red Top\" hoặc \"Black Top\") được tôn sùng vì tiềm năng độ chế khổng lồ, là động cơ tiêu chuẩn cho xe drift.', '2026-04-24 04:06:51', 0, 5, 1, NULL, NULL),
(88, 'Nissan', 'Silvia S14', '1:32', 280000.00, 'Xanh Dương Đậm', 50, 'nissan_silvia_s14_dark_blue.jpg', 'S14 là thế hệ thứ hai của dòng S-chassis được quốc tế hóa, mang lại sự tinh tế và trưởng thành hơn về thiết kế.S14 tiếp tục sử dụng động cơ SR20DET và KA24DE, nhưng đã có những cải tiến đáng kể.Nhờ kích thước lớn hơn và chiều dài cơ sở dài hơn, S14 được đánh giá là ổn định hơn S13 ở tốc độ cao, nhưng vẫn giữ được sự cân bằng RWD tuyệt vời.', '2026-04-24 04:14:23', 0, 5, 1, NULL, NULL),
(89, 'Nissan', 'Silvia S14', '1:32', 260000.00, 'Xanh Dương', 50, 'nissan_silvia_s14_blue.jpg', 'S14 là thế hệ thứ hai của dòng S-chassis được quốc tế hóa, mang lại sự tinh tế và trưởng thành hơn về thiết kế.S14 tiếp tục sử dụng động cơ SR20DET và KA24DE, nhưng đã có những cải tiến đáng kể.Nhờ kích thước lớn hơn và chiều dài cơ sở dài hơn, S14 được đánh giá là ổn định hơn S13 ở tốc độ cao, nhưng vẫn giữ được sự cân bằng RWD tuyệt vời.', '2026-04-24 04:14:23', 0, 5, 1, NULL, NULL),
(90, 'Nissan', 'Silvia S14', '1:32', 250000.00, 'Tím', 50, 'nissan_silvia_s14_purple.jpg', 'S14 là thế hệ thứ hai của dòng S-chassis được quốc tế hóa, mang lại sự tinh tế và trưởng thành hơn về thiết kế.S14 tiếp tục sử dụng động cơ SR20DET và KA24DE, nhưng đã có những cải tiến đáng kể.Nhờ kích thước lớn hơn và chiều dài cơ sở dài hơn, S14 được đánh giá là ổn định hơn S13 ở tốc độ cao, nhưng vẫn giữ được sự cân bằng RWD tuyệt vời.', '2026-04-24 04:14:23', 0, 5, 1, NULL, NULL),
(91, 'Nissan', 'GTR R35 Nismo', '1:32', 300000.00, 'Xanh Dương', 60, 'nissan_gtr_r35_nismo_blue.jpg', 'Nissan GT-R R35 NISMO là đỉnh cao về hiệu suất và công nghệ trong dòng xe GT-R hiện đại. Nó đại diện cho sự kết hợp giữa kỹ thuật tiên tiến của Nissan và kinh nghiệm đua xe hàng thập kỷ của bộ phận hiệu suất cao NISMO (Nissan Motorsports International).Nissan GT-R R35 NISMO không chỉ là một chiếc xe nhanh; nó là một kiệt tác kỹ thuật số, được chế tạo để thống trị trên đường đua, kết hợp sức mạnh động cơ tuyệt đối với khí động học tiên tiến và khả năng xử lý của xe đua chuyên nghiệp.', '2026-04-24 04:22:00', 0, 5, 1, NULL, NULL),
(92, 'Nissan', 'GTR R35 Nismo', '1:32', 350000.00, 'Tím', 40, 'nissan_gtr_r35_nismo_purple.jpg', 'Nissan GT-R R35 NISMO là đỉnh cao về hiệu suất và công nghệ trong dòng xe GT-R hiện đại. Nó đại diện cho sự kết hợp giữa kỹ thuật tiên tiến của Nissan và kinh nghiệm đua xe hàng thập kỷ của bộ phận hiệu suất cao NISMO (Nissan Motorsports International).Nissan GT-R R35 NISMO không chỉ là một chiếc xe nhanh; nó là một kiệt tác kỹ thuật số, được chế tạo để thống trị trên đường đua, kết hợp sức mạnh động cơ tuyệt đối với khí động học tiên tiến và khả năng xử lý của xe đua chuyên nghiệp.', '2026-04-24 04:22:00', 0, 5, 1, NULL, NULL),
(93, 'Nissan', 'GTR R35 Nismo', '1:32', 290000.00, 'Xanh Dương Đậm', 60, 'nissan_gtr_r35_nismo_dark_blue.jpg', 'Nissan GT-R R35 NISMO là đỉnh cao về hiệu suất và công nghệ trong dòng xe GT-R hiện đại. Nó đại diện cho sự kết hợp giữa kỹ thuật tiên tiến của Nissan và kinh nghiệm đua xe hàng thập kỷ của bộ phận hiệu suất cao NISMO (Nissan Motorsports International).Nissan GT-R R35 NISMO không chỉ là một chiếc xe nhanh; nó là một kiệt tác kỹ thuật số, được chế tạo để thống trị trên đường đua, kết hợp sức mạnh động cơ tuyệt đối với khí động học tiên tiến và khả năng xử lý của xe đua chuyên nghiệp.', '2026-04-24 04:22:00', 0, 5, 1, NULL, NULL),
(94, 'Nissan', 'GTR R35 Nismo', '1:32', 280000.00, 'Đỏ', 60, 'nissan_gtr_r35_nismo_red.jpg', 'Nissan GT-R R35 NISMO là đỉnh cao về hiệu suất và công nghệ trong dòng xe GT-R hiện đại. Nó đại diện cho sự kết hợp giữa kỹ thuật tiên tiến của Nissan và kinh nghiệm đua xe hàng thập kỷ của bộ phận hiệu suất cao NISMO (Nissan Motorsports International).Nissan GT-R R35 NISMO không chỉ là một chiếc xe nhanh; nó là một kiệt tác kỹ thuật số, được chế tạo để thống trị trên đường đua, kết hợp sức mạnh động cơ tuyệt đối với khí động học tiên tiến và khả năng xử lý của xe đua chuyên nghiệp.', '2026-04-24 04:22:00', 0, 5, 1, NULL, NULL),
(95, 'Nissan', 'GTR R32 Skyline', '1:32', 280000.00, 'Trắng', 50, 'nissan_gtr_r32_skyline_white.jpg', 'R32 đánh dấu sự trở lại của tên gọi GT-R sau 16 năm vắng bóng. Nissan đã quyết tâm tạo ra chiếc xe thống trị các giải đua Group A.Chiếc xe được mệnh danh là \"Godzilla\" (quái vật từ Nhật Bản) bởi tạp chí Wheels của Úc sau khi nó hoàn toàn áp đảo các đối thủ tại giải đua ATCC (Australian Touring Car Championship). R32 đã bất bại trong 29 chặng đua liên tiếp!', '2026-04-24 04:27:49', 0, 5, 1, NULL, NULL),
(96, 'Nissan', 'GTR R32 Skyline', '1:32', 270000.00, 'Trắng Xám', 50, 'nissan_gtr_r32_skyline_gray.jpg', 'R32 đánh dấu sự trở lại của tên gọi GT-R sau 16 năm vắng bóng. Nissan đã quyết tâm tạo ra chiếc xe thống trị các giải đua Group A.Chiếc xe được mệnh danh là \"Godzilla\" (quái vật từ Nhật Bản) bởi tạp chí Wheels của Úc sau khi nó hoàn toàn áp đảo các đối thủ tại giải đua ATCC (Australian Touring Car Championship). R32 đã bất bại trong 29 chặng đua liên tiếp!', '2026-04-24 04:27:49', 0, 5, 1, NULL, NULL),
(97, 'Nissan', 'GTR R32 Skyline', '1:32', 290000.00, 'Tím', 50, 'nissan_gtr_r32_skyline_purple.jpg', 'R32 đánh dấu sự trở lại của tên gọi GT-R sau 16 năm vắng bóng. Nissan đã quyết tâm tạo ra chiếc xe thống trị các giải đua Group A.Chiếc xe được mệnh danh là \"Godzilla\" (quái vật từ Nhật Bản) bởi tạp chí Wheels của Úc sau khi nó hoàn toàn áp đảo các đối thủ tại giải đua ATCC (Australian Touring Car Championship). R32 đã bất bại trong 29 chặng đua liên tiếp!', '2026-04-24 04:27:49', 0, 5, 1, NULL, NULL),
(98, 'Nissan', 'GTR R32 Skyline', '1:32', 280000.00, 'Đỏ', 50, 'nissan_gtr_r32_skyline_red.jpg', 'R32 đánh dấu sự trở lại của tên gọi GT-R sau 16 năm vắng bóng. Nissan đã quyết tâm tạo ra chiếc xe thống trị các giải đua Group A.Chiếc xe được mệnh danh là \"Godzilla\" (quái vật từ Nhật Bản) bởi tạp chí Wheels của Úc sau khi nó hoàn toàn áp đảo các đối thủ tại giải đua ATCC (Australian Touring Car Championship). R32 đã bất bại trong 29 chặng đua liên tiếp!', '2026-04-24 04:27:49', 0, 5, 1, NULL, NULL),
(99, 'Nissan', 'GTR R34 Skyline', '1:32', 290000.00, 'Xanh Dương', 40, 'nissan_gtr_r34_skyline_blue.jpg', 'Nissan Skyline GT-R R34 (1999–2002) có lẽ là chiếc xe mang tính biểu tượng và được khao khát nhất trong toàn bộ dòng xe GT-R. Nó đại diện cho sự kết hợp hoàn hảo giữa phong cách thiết kế mạnh mẽ, công nghệ tiên tiến, và sự thống trị về hiệu suất.Danh tiếng của R34 được củng cố vững chắc nhờ sự xuất hiện nổi bật trong các trò chơi điện tử (như Gran Turismo) và đặc biệt là bộ phim \"The Fast and the Furious\" với nhân vật Brian O Conner.', '2026-04-24 04:38:16', 0, 5, 1, NULL, NULL),
(100, 'Nissan', 'GTR R34 Skyline', '1:32', 300000.00, 'Xanh Dương Đen', 40, 'nissan_gtr_r34_skyline_black_blue.jpg', 'Nissan Skyline GT-R R34 (1999–2002) có lẽ là chiếc xe mang tính biểu tượng và được khao khát nhất trong toàn bộ dòng xe GT-R. Nó đại diện cho sự kết hợp hoàn hảo giữa phong cách thiết kế mạnh mẽ, công nghệ tiên tiến, và sự thống trị về hiệu suất.Danh tiếng của R34 được củng cố vững chắc nhờ sự xuất hiện nổi bật trong các trò chơi điện tử (như Gran Turismo) và đặc biệt là bộ phim \"The Fast and the Furious\" với nhân vật Brian O Conner.', '2026-04-24 04:38:16', 0, 5, 1, NULL, NULL),
(101, 'Nissan', 'GTR R34 Skyline', '1:32', 350000.00, 'Vàng', 40, 'nissan_gtr_r34_skyline_yellow.jpg', 'Nissan Skyline GT-R R34 (1999–2002) có lẽ là chiếc xe mang tính biểu tượng và được khao khát nhất trong toàn bộ dòng xe GT-R. Nó đại diện cho sự kết hợp hoàn hảo giữa phong cách thiết kế mạnh mẽ, công nghệ tiên tiến, và sự thống trị về hiệu suất.Danh tiếng của R34 được củng cố vững chắc nhờ sự xuất hiện nổi bật trong các trò chơi điện tử (như Gran Turismo) và đặc biệt là bộ phim \"The Fast and the Furious\" với nhân vật Brian O Conner.', '2026-04-24 04:38:16', 0, 5, 1, NULL, NULL),
(102, 'Nissan', 'GTR R34 Skyline', '1:32', 290000.00, 'Đỏ', 40, 'nissan_gtr_r34_skyline_red.jpg', 'Nissan Skyline GT-R R34 (1999–2002) có lẽ là chiếc xe mang tính biểu tượng và được khao khát nhất trong toàn bộ dòng xe GT-R. Nó đại diện cho sự kết hợp hoàn hảo giữa phong cách thiết kế mạnh mẽ, công nghệ tiên tiến, và sự thống trị về hiệu suất.Danh tiếng của R34 được củng cố vững chắc nhờ sự xuất hiện nổi bật trong các trò chơi điện tử (như Gran Turismo) và đặc biệt là bộ phim \"The Fast and the Furious\" với nhân vật Brian O Conner.', '2026-04-24 04:38:16', 0, 5, 1, NULL, NULL),
(103, 'Nissan', '180SX', '1:32', 240000.00, 'Đen', 50, 'nissan_silvia_180sx_black.jpg', 'Nissan 180SX là một chiếc xe rất nổi tiếng, đặc biệt trong cộng đồng drift, và là phiên bản hatchback (mũi gấp) của chiếc Silvia S13 tại thị trường Nhật Bản.Nó được tôn sùng vì tính thẩm mỹ JDM cổ điển, độ bền cơ khí và khả năng điều khiển tuyệt vời, là một trong những biểu tượng vĩ đại nhất của lịch sử xe drift.', '2026-04-24 06:53:32', 0, 5, 1, NULL, NULL);
INSERT INTO `products` (`id`, `brand`, `model`, `scale`, `price`, `color`, `stock`, `image`, `description`, `created_at`, `sold_count`, `low_stock_threshold`, `is_active`, `deleted_at`, `embedding`) VALUES
(104, 'Nissan', '180SX', '1:32', 250000.00, 'Xám', 50, 'nissan_silvia_180sx_gray.jpg', 'Nissan 180SX là một chiếc xe rất nổi tiếng, đặc biệt trong cộng đồng drift, và là phiên bản hatchback (mũi gấp) của chiếc Silvia S13 tại thị trường Nhật Bản.Nó được tôn sùng vì tính thẩm mỹ JDM cổ điển, độ bền cơ khí và khả năng điều khiển tuyệt vời, là một trong những biểu tượng vĩ đại nhất của lịch sử xe drift.', '2026-04-24 06:53:32', 0, 5, 1, NULL, NULL),
(105, 'Mitsubishi', 'Lancer Evo VI', '1:32', 240000.00, 'Xanh Dương', 50, 'mitsubishi_lancer_evo_vi_blue.jpg', 'Evo VI là thế hệ được coi là đỉnh cao của thiết kế Rally và là một trong những chiếc Evo được yêu thích nhất.Tiếp tục là 4G63T với công suất 280 PS.Cải tiến lớn nhất là pít-tông nhẹ hơn và hệ thống làm mát/độ bền được nâng cấp để chịu được cường độ đua Rally cao.', '2026-04-24 07:32:09', 0, 5, 1, NULL, NULL),
(106, 'Mitsubishi', 'Lancer Evo VI', '1:32', 220000.00, 'Trắng', 50, 'mitsubishi_lancer_evo_vi_white.jpg', 'Evo VI là thế hệ được coi là đỉnh cao của thiết kế Rally và là một trong những chiếc Evo được yêu thích nhất.Tiếp tục là 4G63T với công suất 280 PS.Cải tiến lớn nhất là pít-tông nhẹ hơn và hệ thống làm mát/độ bền được nâng cấp để chịu được cường độ đua Rally cao.', '2026-04-24 07:32:09', 0, 5, 1, NULL, NULL),
(107, 'Mitsubishi', 'Lancer Evo III', '1:32', 240000.00, 'Trắng Đỏ', 50, 'mitsubishi_lancer_evo_iii_white_red.jpg', 'Evo III là phiên bản cuối cùng và hoàn thiện nhất của thế hệ Evo đầu tiên (bao gồm Evo I và II), được nhớ đến là chiếc xe đã mang lại danh hiệu vô địch WRC đầu tiên cho Tommi Mäkinen.Tiếp tục sử dụng động cơ huyền thoại 4G63T 2.0L, I4, Tăng áp.Công suất được tăng lên tới 270 PS (~266 HP), nhờ vào việc tăng tỷ số nén (compression ratio) và thiết kế turbocharger cải tiến.', '2026-04-24 07:37:21', 0, 5, 1, NULL, NULL),
(108, 'Mitsubishi', 'Eclipse', '1:32', 250000.00, 'Xanh Dương Đen', 50, 'mitsubishi_eclipse_black_blue.jpg', 'Mitsubishi Eclipse là một dòng xe thể thao compact coupe rất phổ biến, đặc biệt là ở thị trường Bắc Mỹ, và có vị thế quan trọng trong phân khúc xe thể thao giá cả phải chăng trong suốt những năm 1990 và 2000.Nó chuyển hướng sang dòng xe FWD Grand Tourer cho đến khi ngừng sản xuất. Dù vậy, Eclipse 1G và 2G vẫn giữ một vị trí đặc biệt trong lịch sử JDM và văn hóa độ xe.', '2026-04-24 07:44:42', 0, 5, 1, NULL, NULL),
(109, 'Mitsubishi', 'Eclipse', '1:32', 260000.00, 'Xanh Dương', 50, 'mitsubishi_eclipse_blue.jpg', 'Mitsubishi Eclipse là một dòng xe thể thao compact coupe rất phổ biến, đặc biệt là ở thị trường Bắc Mỹ, và có vị thế quan trọng trong phân khúc xe thể thao giá cả phải chăng trong suốt những năm 1990 và 2000.Nó chuyển hướng sang dòng xe FWD Grand Tourer cho đến khi ngừng sản xuất. Dù vậy, Eclipse 1G và 2G vẫn giữ một vị trí đặc biệt trong lịch sử JDM và văn hóa độ xe.', '2026-04-24 07:44:42', 0, 5, 1, NULL, NULL),
(110, 'Mitsubishi', 'Eclipse', '1:32', 260000.00, 'Vàng', 50, 'mitsubishi_eclipse_yellow.jpg', 'Mitsubishi Eclipse là một dòng xe thể thao compact coupe rất phổ biến, đặc biệt là ở thị trường Bắc Mỹ, và có vị thế quan trọng trong phân khúc xe thể thao giá cả phải chăng trong suốt những năm 1990 và 2000.Nó chuyển hướng sang dòng xe FWD Grand Tourer cho đến khi ngừng sản xuất. Dù vậy, Eclipse 1G và 2G vẫn giữ một vị trí đặc biệt trong lịch sử JDM và văn hóa độ xe.', '2026-04-24 07:44:42', 0, 5, 1, NULL, NULL),
(111, 'Mazda', 'RX7 FD', '1:32', 290000.00, 'Xám', 50, 'mazda_rx7_fd_gray.jpg', 'FD3S là đỉnh cao của thiết kế RX-7 và được coi là một trong những chiếc xe đẹp nhất từng được sản xuất.FD là biểu tượng của công nghệ động cơ Rotary hiện đại và là một trong những chiếc xe JDM được săn lùng và có giá trị nhất, nổi tiếng về cả vẻ đẹp lẫn tiềm năng độ chế.', '2026-04-24 07:55:08', 0, 5, 1, NULL, NULL),
(112, 'Mazda', 'RX7 FD', '1:32', 280000.00, 'Đen', 50, 'mazda_rx7_fd_black.jpg', 'FD3S là đỉnh cao của thiết kế RX-7 và được coi là một trong những chiếc xe đẹp nhất từng được sản xuất.FD là biểu tượng của công nghệ động cơ Rotary hiện đại và là một trong những chiếc xe JDM được săn lùng và có giá trị nhất, nổi tiếng về cả vẻ đẹp lẫn tiềm năng độ chế.', '2026-04-24 07:55:08', 0, 5, 1, NULL, NULL),
(113, 'Mazda', 'RX7 FD', '1:32', 280000.00, 'Đỏ', 48, 'mazda_rx7_fd_red.jpg', 'FD3S là đỉnh cao của thiết kế RX-7 và được coi là một trong những chiếc xe đẹp nhất từng được sản xuất.FD là biểu tượng của công nghệ động cơ Rotary hiện đại và là một trong những chiếc xe JDM được săn lùng và có giá trị nhất, nổi tiếng về cả vẻ đẹp lẫn tiềm năng độ chế.', '2026-04-24 07:55:08', 0, 5, 1, NULL, NULL),
(114, 'Mazda', 'RX7 FD', '1:32', 260000.00, 'Hồng Xanh Dương', 50, 'mazda_rx7_fd_blue_pink.jpg', 'FD3S là đỉnh cao của thiết kế RX-7 và được coi là một trong những chiếc xe đẹp nhất từng được sản xuất.FD là biểu tượng của công nghệ động cơ Rotary hiện đại và là một trong những chiếc xe JDM được săn lùng và có giá trị nhất, nổi tiếng về cả vẻ đẹp lẫn tiềm năng độ chế.', '2026-04-24 07:55:08', 0, 5, 1, NULL, NULL),
(115, 'Mazda', 'RX7 FD', '1:32', 290000.00, 'Đen Xanh Dương', 50, 'mazda_rx7_fd_black_blue.jpg', 'FD3S là đỉnh cao của thiết kế RX-7 và được coi là một trong những chiếc xe đẹp nhất từng được sản xuất.FD là biểu tượng của công nghệ động cơ Rotary hiện đại và là một trong những chiếc xe JDM được săn lùng và có giá trị nhất, nổi tiếng về cả vẻ đẹp lẫn tiềm năng độ chế.', '2026-04-24 07:55:08', 0, 5, 1, NULL, NULL),
(116, 'Mazda', 'RX7 FC', '1:32', 300000.00, 'Trắng Xanh Dương', 50, 'mazda_rx7_fc_white_blue.jpg', 'FC3S là thế hệ đã giúp RX-7 trở thành đối thủ cạnh tranh trực tiếp với các mẫu xe thể thao lớn của thế giới, đặc biệt là Porsche.FC là chiếc RX-7 đầu tiên đạt được danh tiếng đáng kể trong các giải đua chuyên nghiệp và là một nền tảng độ chế được yêu thích.', '2026-04-24 08:01:42', 0, 5, 1, NULL, NULL),
(117, 'Mazda', 'RX7 FC', '1:32', 310000.00, 'Trắng Tím', 50, 'mazda_rx7_fc_white_purple.jpg', 'FC3S là thế hệ đã giúp RX-7 trở thành đối thủ cạnh tranh trực tiếp với các mẫu xe thể thao lớn của thế giới, đặc biệt là Porsche.FC là chiếc RX-7 đầu tiên đạt được danh tiếng đáng kể trong các giải đua chuyên nghiệp và là một nền tảng độ chế được yêu thích.', '2026-04-24 08:01:42', 0, 5, 1, NULL, NULL),
(118, 'Mazda', 'RX7 FC', '1:32', 280000.00, 'Xanh Dương', 50, 'mazda_rx7_fc_blue.jpg', 'FC3S là thế hệ đã giúp RX-7 trở thành đối thủ cạnh tranh trực tiếp với các mẫu xe thể thao lớn của thế giới, đặc biệt là Porsche.FC là chiếc RX-7 đầu tiên đạt được danh tiếng đáng kể trong các giải đua chuyên nghiệp và là một nền tảng độ chế được yêu thích.', '2026-04-24 08:01:42', 0, 5, 1, NULL, NULL),
