(129, 'Honda', 'S2000', '1:32', 350000.00, 'Vàng', 50, 'honda_s2000_yellow.jpg', 'Honda S2000 là một trong những chiếc roadster (xe mui trần hai chỗ) mang tính biểu tượng nhất của Honda, được phát triển để kỷ niệm 50 năm thành lập công ty. Nó nổi tiếng với triết lý kỹ thuật cực kỳ tiên tiến, đặc biệt là động cơ vòng tua máy siêu cao.Honda S2000 là một kiệt tác kỹ thuật. Nó nổi bật với động cơ VTEC 9000 RPM (trên AP1), khả năng xử lý sắc nét, và khung gầm siêu cứng, định nghĩa lại trải nghiệm lái xe mui trần hiệu suất cao.', '2026-04-24 08:16:47', 0, 5, 1, NULL, NULL),
(130, 'Honda', 'Civic EG6 Vtec', '1:32', 290000.00, 'Hồng', 50, 'honda_civic_eg6_pink.jpg', 'EG6 là phiên bản hiệu suất cao của Civic thế hệ thứ năm (EG), được tôn sùng vì kiểu dáng mềm mại, nhẹ nhàng và khả năng xử lý tuyệt vời.B16A 1.6L, I4, DOHC VTEC.Sản sinh công suất khoảng 160 PS (158 HP).EG6 cực kỳ nhẹ (thường dưới 1.000 kg), kết hợp với hệ thống treo độc lập bốn bánh, mang lại cảm giác lái rất linh hoạt và trực tiếp.Nhiều người hâm mộ đánh giá cao EG6 vì sự đơn giản cơ học và khả năng độ chế dễ dàng, biến nó thành một chiếc xe đua đường phố hoặc đường đua rất hiệu quả.', '2026-04-24 13:00:17', 0, 5, 1, NULL, NULL),
(131, 'Honda', 'Civic EG6 Vtec', '1:32', 280000.00, 'Đen', 50, 'honda_civic_eg6_black.jpg', 'EG6 là phiên bản hiệu suất cao của Civic thế hệ thứ năm (EG), được tôn sùng vì kiểu dáng mềm mại, nhẹ nhàng và khả năng xử lý tuyệt vời.B16A 1.6L, I4, DOHC VTEC.Sản sinh công suất khoảng 160 PS (158 HP).EG6 cực kỳ nhẹ (thường dưới 1.000 kg), kết hợp với hệ thống treo độc lập bốn bánh, mang lại cảm giác lái rất linh hoạt và trực tiếp.Nhiều người hâm mộ đánh giá cao EG6 vì sự đơn giản cơ học và khả năng độ chế dễ dàng, biến nó thành một chiếc xe đua đường phố hoặc đường đua rất hiệu quả.', '2026-04-24 13:00:17', 0, 5, 1, NULL, NULL),
(132, 'Honda', 'Civic EG6 Vtec', '1:32', 287000.00, 'Xanh Dương Đen', 50, 'honda_civic_eg6_black_blue.jpg', 'EG6 là phiên bản hiệu suất cao của Civic thế hệ thứ năm (EG), được tôn sùng vì kiểu dáng mềm mại, nhẹ nhàng và khả năng xử lý tuyệt vời.B16A 1.6L, I4, DOHC VTEC.Sản sinh công suất khoảng 160 PS (158 HP).EG6 cực kỳ nhẹ (thường dưới 1.000 kg), kết hợp với hệ thống treo độc lập bốn bánh, mang lại cảm giác lái rất linh hoạt và trực tiếp.Nhiều người hâm mộ đánh giá cao EG6 vì sự đơn giản cơ học và khả năng độ chế dễ dàng, biến nó thành một chiếc xe đua đường phố hoặc đường đua rất hiệu quả.', '2026-04-24 13:00:17', 0, 5, 1, NULL, NULL),
(133, 'Honda', 'Civic EG6 Vtec', '1:32', 260000.00, 'Vàng', 50, 'honda_civic_eg6_yellow.jpg', 'EG6 là phiên bản hiệu suất cao của Civic thế hệ thứ năm (EG), được tôn sùng vì kiểu dáng mềm mại, nhẹ nhàng và khả năng xử lý tuyệt vời.B16A 1.6L, I4, DOHC VTEC.Sản sinh công suất khoảng 160 PS (158 HP).EG6 cực kỳ nhẹ (thường dưới 1.000 kg), kết hợp với hệ thống treo độc lập bốn bánh, mang lại cảm giác lái rất linh hoạt và trực tiếp.Nhiều người hâm mộ đánh giá cao EG6 vì sự đơn giản cơ học và khả năng độ chế dễ dàng, biến nó thành một chiếc xe đua đường phố hoặc đường đua rất hiệu quả.', '2026-04-24 13:00:17', 0, 5, 1, NULL, NULL),
(134, 'Honda', 'Civic Type R EK9', '1:32', 290000.00, 'Trắng', 47, 'honda_civic_ek9_white.jpg', 'EK9 là chiếc Civic đầu tiên mang biểu tượng \"Type R\" (Racing) và được coi là định nghĩa cho triết lý xe thể thao FWD (Dẫn động cầu trước) của Honda.B16B 1.6L, I4, DOHC VTEC.Sản sinh 185 PS (182 HP) tại vòng tua máy cực cao, thường là 8,200 RPM.B16B là một phiên bản được tinh chỉnh thủ công từ B16A, với thanh truyền dài hơn, pít-tông nhẹ hơn và đầu xi-lanh được cân bằng hoàn hảo.Trang bị Bộ vi sai chống trượt Helical (LSD) tiêu chuẩn, giúp phân bổ lực kéo hiệu quả hơn nhiều, đặc biệt khi vào cua gắt, biến nó thành một cỗ máy xử lý FWD cực kỳ nhanh nhẹn.', '2026-04-24 13:07:30', 0, 5, 1, NULL, NULL),
(135, 'Honda', 'Civic Type R EK9', '1:32', 320000.00, 'Trắng Đen', 55, 'honda_civic_ek9_black_white.png', 'EK9 là chiếc Civic đầu tiên mang biểu tượng \"Type R\" (Racing) và được coi là định nghĩa cho triết lý xe thể thao FWD (Dẫn động cầu trước) của Honda.B16B 1.6L, I4, DOHC VTEC.Sản sinh 185 PS (182 HP) tại vòng tua máy cực cao, thường là 8,200 RPM.B16B là một phiên bản được tinh chỉnh thủ công từ B16A, với thanh truyền dài hơn, pít-tông nhẹ hơn và đầu xi-lanh được cân bằng hoàn hảo.Trang bị Bộ vi sai chống trượt Helical (LSD) tiêu chuẩn, giúp phân bổ lực kéo hiệu quả hơn nhiều, đặc biệt khi vào cua gắt, biến nó thành một cỗ máy xử lý FWD cực kỳ nhanh nhẹn.', '2026-04-24 13:07:30', 0, 5, 1, NULL, NULL),
(136, 'Honda', 'Civic Type R EK9', '1:32', 360000.00, 'Đỏ', 48, 'honda_civic_ek9_red.jpg', 'EK9 là chiếc Civic đầu tiên mang biểu tượng \"Type R\" (Racing) và được coi là định nghĩa cho triết lý xe thể thao FWD (Dẫn động cầu trước) của Honda.B16B 1.6L, I4, DOHC VTEC.Sản sinh 185 PS (182 HP) tại vòng tua máy cực cao, thường là 8,200 RPM.B16B là một phiên bản được tinh chỉnh thủ công từ B16A, với thanh truyền dài hơn, pít-tông nhẹ hơn và đầu xi-lanh được cân bằng hoàn hảo.Trang bị Bộ vi sai chống trượt Helical (LSD) tiêu chuẩn, giúp phân bổ lực kéo hiệu quả hơn nhiều, đặc biệt khi vào cua gắt, biến nó thành một cỗ máy xử lý FWD cực kỳ nhanh nhẹn.', '2026-04-24 13:07:30', 0, 5, 1, NULL, NULL);

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `product_images`
--

DROP TABLE IF EXISTS `product_images`;
CREATE TABLE IF NOT EXISTS `product_images` (
  `id` int NOT NULL AUTO_INCREMENT,
  `product_id` int NOT NULL,
  `image_url` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  PRIMARY KEY (`id`),
  KEY `product_id` (`product_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `recommendation_logs`
--

DROP TABLE IF EXISTS `recommendation_logs`;
CREATE TABLE IF NOT EXISTS `recommendation_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int DEFAULT NULL,
  `product_id` int DEFAULT NULL,
  `score` float DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `product_id` (`product_id`),
  KEY `user_id` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `returns`
--

DROP TABLE IF EXISTS `returns`;
CREATE TABLE IF NOT EXISTS `returns` (
  `id` int NOT NULL AUTO_INCREMENT,
  `order_id` int NOT NULL,
  `user_id` int NOT NULL,
  `request_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'return',
  `reason` text COLLATE utf8mb4_unicode_ci,
  `resolution_note` text COLLATE utf8mb4_unicode_ci,
  `image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('pending','approved','rejected','completed') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `order_id` (`order_id`),
  KEY `user_id` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `reviews`
--

DROP TABLE IF EXISTS `reviews`;
CREATE TABLE IF NOT EXISTS `reviews` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `product_id` int NOT NULL,
  `order_id` int NOT NULL,
  `rating` int NOT NULL,
  `comment` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `reviews_user_product_unique` (`user_id`,`product_id`),
  KEY `user_id` (`user_id`),
  KEY `product_id` (`product_id`),
  KEY `order_id` (`order_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `review_images`
--

DROP TABLE IF EXISTS `review_images`;
CREATE TABLE IF NOT EXISTS `review_images` (
  `id` int NOT NULL AUTO_INCREMENT,
  `review_id` int NOT NULL,
  `image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `review_id` (`review_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `search_histories`
--

DROP TABLE IF EXISTS `search_histories`;
CREATE TABLE IF NOT EXISTS `search_histories` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int DEFAULT NULL,
  `keyword` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `sessions`
--

DROP TABLE IF EXISTS `sessions`;
CREATE TABLE IF NOT EXISTS `sessions` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` int DEFAULT NULL,
